# Policy test for telemetry wiring: checkout event must include required privacy fields
import pytest

from telemetry import (
    REQUIRED_PRIVACY_FIELDS,
    TelemetryPolicyError,
    emit_checkout_event,
)


def _valid_event():
    return {
        "consent": True,
        "pii_redacted": True,
        "data_classification": "restricted",
        "retention_days": 30,
        "region": "us-east-1",
    }


def test_valid_checkout_event_passes():
    assert emit_checkout_event(_valid_event()) == _valid_event()


@pytest.mark.parametrize("field", REQUIRED_PRIVACY_FIELDS)
def test_missing_required_field_rejected(field):
    ev = _valid_event()
    del ev[field]
    with pytest.raises(TelemetryPolicyError):
        emit_checkout_event(ev)


@pytest.mark.parametrize("field", REQUIRED_PRIVACY_FIELDS)
def test_none_required_field_rejected(field):
    ev = _valid_event()
    ev[field] = None
    with pytest.raises(TelemetryPolicyError):
        emit_checkout_event(ev)


def test_consent_must_be_true():
    ev = _valid_event()
    ev["consent"] = False
    with pytest.raises(TelemetryPolicyError):
        emit_checkout_event(ev)


def test_pii_redacted_must_be_true():
    ev = _valid_event()
    ev["pii_redacted"] = False
    with pytest.raises(TelemetryPolicyError):
        emit_checkout_event(ev)

